import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';
import {
  closeAllNonHomeDockTabs,
  openEnhancedResource as sharedOpenEnhancedResource,
} from './test-helpers';

// Feature: enhanced-resources
// Work Package: UI-PKG-008: MarbleGuideForm (Getting Started Guide)
// Generated by: ui-test-writer (RED phase — all tests use test.fixme)
//
// Coverage:
//   - Test scenarios: TS-065 (auto-show first session), TS-066 (suppressed), TS-067 (no second show)
//   - Behaviors: BHV-461 (first-time guide display logic), BHV-463 (ER window creation triggers
//     auto-show check)
//   - Forward notes: FN-016 (info-icon button opens guide via registered command — UI-PKG-001
//     toolbar triggers, UI-PKG-008 is the target dialog)
//
// Architecture (per strategic-plan-ui.md UI-PKG-008, Theme 14 revision):
//   - MarbleGuide is rendered via paranext-core overlay-service Dialog (app-wide), NOT a webview.
//   - Trigger: info-icon button on the MarbleForm upper toolbar (UI-PKG-001 component); also
//     auto-shown on first ER open per session when ShowMarbleGuide setting is true.
//   - Persistence: extension settings API (`ShowMarbleGuide` boolean). "Don't show this again" sets
//     ShowMarbleGuide=false on close.
//   - Selectors come from the existing presentational component (phase-3-ui-design output);
//     phase-3-ui implementation wires the dialog into the toolbar handler + auto-show + settings.
//
// Selectors (from Test Contract + actual component data-testids):
//   - marble-guide                     — DialogContent root
//   - marble-guide-title               — DialogTitle ("Getting started in enhanced resources")
//   - marble-guide-content             — Scrollable HTML body
//   - marble-guide-color-chip-blue     — Blue research-term color chip
//   - marble-guide-color-chip-gray     — Gray needs-rendering color chip
//   - marble-guide-color-chip-orange   — Orange found-rendering color chip
//   - marble-guide-tab-grid            — Research tab icon descriptions block
//   - marble-guide-close               — Close button
//   - marble-guide-never-show-again    — "Don't show this again" Checkbox
//
// Note: Because MarbleGuide is rendered via the overlay-service Dialog at the app level, all
// selectors live on `mainPage`, not in an iframe (no `frameLocator` needed).

test.describe('Enhanced Resources Functional Tests (UI-PKG-008)', () => {
  test.beforeEach(async ({ mainPage }) => {
    await closeAllNonHomeDockTabs(mainPage);
  });

  /**
   * Opens an Enhanced Resource window. Delegates to the shared helper which uses the hardcoded
   * ESV16UK+ default (TODO(GAP-001)) and dismisses the auto-shown MarbleGuide if it appears.
   *
   * UI-PKG-008 specifically wants to OBSERVE the MarbleGuide auto-show, so it disables the
   * automatic dismissal by passing `dismissGuide: false`.
   */
  const openEnhancedResource = (
    mainPage: import('@playwright/test').Page,
    options: { dismissGuide?: boolean } = { dismissGuide: false },
  ) => sharedOpenEnhancedResource(mainPage, options);

  // ═══════════════════════════════════════════════
  // Category 1: Navigation
  // ═══════════════════════════════════════════════

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing - haveShownMarbleGuide in extension-host memory persists across tests; only the FIRST test in a fresh app session can observe the auto-show.
  // @scenario TS-065
  test.fixme(
    'should auto-show MarbleGuide on first Enhanced Resource open per session',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Precondition: ShowMarbleGuide setting is at default (true), session is fresh.
      // Open an ER — phase-3-ui wiring should auto-show the guide on this first open.
      await openEnhancedResource(mainPage);

      // EVD-010: Guide auto-shows on first ER open this session.
      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });
      await mainPage.screenshot({
        path: 'proofs/component-evidence/UI-PKG-008/EVD-010-guide-auto-shown.png',
      });

      // The "Don't show this again" checkbox starts unchecked (initial state = !showGuide,
      // and showGuide=true on a fresh install).
      const checkbox = mainPage.getByTestId('marble-guide-never-show-again');
      await expect(checkbox).not.toBeChecked();
    },
  );

  // ═══════════════════════════════════════════════
  // Category 2: Render
  // ═══════════════════════════════════════════════

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing - relies on auto-show that only fires on first ER open per session.
  // @scenario TS-065
  test.fixme(
    'should render all required guide sections (title, content, color chips, tab grid, close, checkbox)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);

      // Wait for auto-show, OR open via info-icon if it didn't auto-show (defensive).
      const guide = mainPage.getByTestId('marble-guide');
      if (!(await guide.isVisible().catch(() => false))) {
        await mainPage
          .getByRole('button', { name: /Show.*Hide.*Enhanced Resource Guide|Info|Guide/i })
          .first()
          .click();
      }
      await expect(guide).toBeVisible({ timeout: 10_000 });

      // DialogTitle ("Getting started in enhanced resources")
      await expect(mainPage.getByTestId('marble-guide-title')).toBeVisible();
      await expect(mainPage.getByTestId('marble-guide-title')).toHaveText(
        /Getting started|Enhanced Resources/i,
      );

      // Scrollable content area
      await expect(mainPage.getByTestId('marble-guide-content')).toBeVisible();

      // Three color chips for research-term / needs-rendering / found-rendering metaphor
      await expect(mainPage.getByTestId('marble-guide-color-chip-blue')).toBeVisible();
      await expect(mainPage.getByTestId('marble-guide-color-chip-gray')).toBeVisible();
      await expect(mainPage.getByTestId('marble-guide-color-chip-orange')).toBeVisible();

      // Research tab icon descriptions grid (Dictionary / Encyclopedia / Media / Maps)
      await expect(mainPage.getByTestId('marble-guide-tab-grid')).toBeVisible();

      // Close button + "Don't show this again" checkbox
      await expect(mainPage.getByTestId('marble-guide-close')).toBeVisible();
      await expect(mainPage.getByTestId('marble-guide-never-show-again')).toBeVisible();

      // EVD-010: Window fully loaded with all expected sections.
      await mainPage.screenshot({
        path: 'proofs/component-evidence/UI-PKG-008/EVD-010-guide-rendered.png',
      });
    },
  );

  // ═══════════════════════════════════════════════
  // Category 3: Data Wiring
  // ═══════════════════════════════════════════════

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing - relies on auto-show that only fires on first ER open per session.
  // @scenario TS-065
  test.fixme(
    'should populate localized strings (title and content not empty / placeholder keys)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);

      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });

      // Title must be a real localized string, not the raw localization key.
      const titleText = (await mainPage.getByTestId('marble-guide-title').textContent()) ?? '';
      expect(titleText.trim()).not.toBe('');
      expect(titleText).not.toContain('%enhancedResources_marbleGuide_title%');

      // Content body must contain real text (overview paragraph).
      const contentText = (await mainPage.getByTestId('marble-guide-content').textContent()) ?? '';
      expect(contentText.trim().length).toBeGreaterThan(50);
      expect(contentText).not.toContain('%enhancedResources_marbleGuide_overview%');

      // Close button label localized.
      const closeText = (await mainPage.getByTestId('marble-guide-close').textContent()) ?? '';
      expect(closeText.trim()).not.toBe('');
      expect(closeText).not.toContain('%enhancedResources_marbleGuide_close%');
    },
  );

  // FIXME(GAP-guide-reset): relies on auto-show that only fires on first ER open per session.
  // @scenario TS-065
  test.fixme(
    'should reflect persisted ShowMarbleGuide setting in checkbox initial state',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);

      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });

      // On a fresh setting (ShowMarbleGuide=true), the checkbox is unchecked
      // (state derives from !showGuide).
      await expect(mainPage.getByTestId('marble-guide-never-show-again')).not.toBeChecked();
    },
  );

  // ═══════════════════════════════════════════════
  // Category 4: Interaction
  // ═══════════════════════════════════════════════

  // @scenario TS-065 (covers FN-016 toggle)
  test('should toggle MarbleGuide open/closed via info-icon button on the MarbleForm toolbar', async ({
    mainPage,
  }) => {
    await waitForAppReady(mainPage);
    await openEnhancedResource(mainPage);

    const guide = mainPage.getByTestId('marble-guide');

    // First-open auto-show — close it so we can test the toggle.
    if (await guide.isVisible().catch(() => false)) {
      await mainPage.getByTestId('marble-guide-close').click();
      await expect(guide).toBeHidden({ timeout: 5_000 });
    }

    // Click the info-icon button on the upper toolbar (FN-016) — should open the guide.
    const infoBtn = mainPage
      .getByRole('button', { name: /Show.*Hide.*Enhanced Resource Guide|Info|Guide/i })
      .first();
    await infoBtn.click();
    await expect(guide).toBeVisible({ timeout: 5_000 });

    // EVD-011: Guide opened by info button click.
    await mainPage.screenshot({
      path: 'proofs/component-evidence/UI-PKG-008/EVD-011-guide-toggled-on.png',
    });

    // Click info-icon again — should close the guide.
    await infoBtn.click();
    await expect(guide).toBeHidden({ timeout: 5_000 });

    // EVD-011: Guide closed by info button click again.
    await mainPage.screenshot({
      path: 'proofs/component-evidence/UI-PKG-008/EVD-011-guide-toggled-off.png',
    });
  });

  // FIXME(GAP-guide-reset): test depends on auto-show being visible at start; only fires on first ER open per session.
  // @scenario TS-065
  test.fixme('should close MarbleGuide via the Close button', async ({ mainPage }) => {
    await waitForAppReady(mainPage);
    await openEnhancedResource(mainPage);

    const guide = mainPage.getByTestId('marble-guide');
    await expect(guide).toBeVisible({ timeout: 10_000 });

    await mainPage.getByTestId('marble-guide-close').click();
    await expect(guide).toBeHidden({ timeout: 5_000 });
  });

  // FIXME(GAP-guide-reset): test depends on auto-show being visible at start; only fires on first ER open per session.
  // @scenario TS-065
  test.fixme('should close MarbleGuide when Escape is pressed', async ({ mainPage }) => {
    await waitForAppReady(mainPage);
    await openEnhancedResource(mainPage);

    const guide = mainPage.getByTestId('marble-guide');
    await expect(guide).toBeVisible({ timeout: 10_000 });

    await mainPage.keyboard.press('Escape');
    await expect(guide).toBeHidden({ timeout: 5_000 });
  });

  // FIXME(GAP-guide-reset): test depends on auto-show being visible at start; only fires on first ER open per session.
  // @scenario TS-065
  test.fixme(
    'should toggle the "Don\'t show this again" checkbox state when clicked',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);

      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });

      const checkbox = mainPage.getByTestId('marble-guide-never-show-again');
      await expect(checkbox).not.toBeChecked();

      await checkbox.click();
      await expect(checkbox).toBeChecked();

      await checkbox.click();
      await expect(checkbox).not.toBeChecked();
    },
  );

  // ═══════════════════════════════════════════════
  // Category 5: Edge Cases (covers TS-066, TS-067)
  // ═══════════════════════════════════════════════

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing; cannot reliably test the suppress-then-reopen flow without state isolation.
  // @scenario TS-066 (BHV-461 + BHV-465)
  test.fixme(
    'should persist ShowMarbleGuide=false when "Don\'t show this again" is checked and Close is clicked, and not auto-show on next ER open',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Open ER — guide auto-shows.
      await openEnhancedResource(mainPage);
      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });

      // Check the "Don't show this again" checkbox and close.
      await mainPage.getByTestId('marble-guide-never-show-again').click();
      await expect(mainPage.getByTestId('marble-guide-never-show-again')).toBeChecked();
      await mainPage.getByTestId('marble-guide-close').click();
      await expect(guide).toBeHidden({ timeout: 5_000 });

      // EVD-012: Setting persisted via "Don't show this again" + Close.
      await mainPage.screenshot({
        path: 'proofs/component-evidence/UI-PKG-008/EVD-012-setting-persisted.png',
      });

      // Close the ER tab and reopen — guide must NOT auto-show because ShowMarbleGuide is now
      // false. (TS-066 — permanently suppressed.)
      const erTabClose = mainPage
        .locator('.dock-tab')
        .filter({ hasText: /Enhanced Resource/i })
        .locator('.dock-tab-close-btn')
        .first();
      await erTabClose.dispatchEvent('click');
      await mainPage.waitForTimeout(500);

      await openEnhancedResource(mainPage);
      // Allow time for any auto-show logic to fire.
      await mainPage.waitForTimeout(2_000);
      await expect(guide).toBeHidden();

      // EVD-012: After reopen, guide does not auto-show.
      await mainPage.screenshot({
        path: 'proofs/component-evidence/UI-PKG-008/EVD-012-no-auto-show-after-suppress.png',
      });
    },
  );

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing; depends on first-open auto-show behavior.
  // @scenario TS-067 (BHV-461 session flag)
  test.fixme(
    'should NOT auto-show MarbleGuide on second Enhanced Resource open in same session',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // First open — guide auto-shows.
      await openEnhancedResource(mainPage);
      const guide = mainPage.getByTestId('marble-guide');
      await expect(guide).toBeVisible({ timeout: 10_000 });

      // Close the guide WITHOUT checking "never show again" (preserve ShowMarbleGuide=true).
      await mainPage.getByTestId('marble-guide-close').click();
      await expect(guide).toBeHidden({ timeout: 5_000 });

      // Close the first ER tab.
      const firstErTabClose = mainPage
        .locator('.dock-tab')
        .filter({ hasText: /Enhanced Resource/i })
        .locator('.dock-tab-close-btn')
        .first();
      await firstErTabClose.dispatchEvent('click');
      await mainPage.waitForTimeout(500);

      // Second open in same session — guide must NOT auto-show because the session-level
      // `haveShownMarbleGuide` flag is already true (BHV-461 / TS-067).
      await openEnhancedResource(mainPage);
      await mainPage.waitForTimeout(2_000);
      await expect(guide).toBeHidden();

      // The user can still toggle the guide manually via the info button — verify reachability.
      const infoBtn = mainPage
        .getByRole('button', { name: /Show.*Hide.*Enhanced Resource Guide|Info|Guide/i })
        .first();
      await infoBtn.click();
      await expect(guide).toBeVisible({ timeout: 5_000 });
    },
  );

  // FIXME(GAP-guide-reset): per-test extension-host reset hook missing; cannot reliably test re-enable flow.
  // @scenario TS-066 (re-enable path — edge case from edge-cases.md "Guide Never Show Again Re-Enable")
  test.fixme(
    'should re-enable ShowMarbleGuide when user opens guide via info button and unchecks "Don\'t show this again"',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Setup: ShowMarbleGuide is false (previously suppressed). Manual open via info button.
      await openEnhancedResource(mainPage);
      const guide = mainPage.getByTestId('marble-guide');

      // Skip any potential auto-show transient — open manually if needed.
      if (!(await guide.isVisible().catch(() => false))) {
        await mainPage
          .getByRole('button', { name: /Show.*Hide.*Enhanced Resource Guide|Info|Guide/i })
          .first()
          .click();
      }
      await expect(guide).toBeVisible({ timeout: 5_000 });

      // The checkbox reflects current ShowMarbleGuide. If suppressed, it should be checked;
      // uncheck it to re-enable.
      const checkbox = mainPage.getByTestId('marble-guide-never-show-again');
      if (await checkbox.isChecked()) {
        await checkbox.click();
        await expect(checkbox).not.toBeChecked();
      }

      await mainPage.getByTestId('marble-guide-close').click();
      await expect(guide).toBeHidden({ timeout: 5_000 });
      // ShowMarbleGuide is now true again — tested separately by re-opening on a fresh session.
    },
  );
});
